    pub fn set_path(&mut self, new_path: Vec<u8>) {
        with_node!(self, ref mut data, data.path = new_path)
    }

    pub fn get_cow_ptr(&self) -> Option<&TrieCowPtr> {
        with_node!(self, ref data, data.get_cow_ptr())
